WITH src AS (SELECT w.checkpoints_timed, w.checkpoints_req AS checkpoints_requested, w.checkpoint_write_time, w.checkpoint_sync_time, w.buffers_checkpoint, w.buffers_clean, w.maxwritten_clean AS max_written_clean, w.buffers_backend, w.buffers_backend_fsync, w.buffers_alloc AS buffers_allocated, w.stats_reset FROM pg_stat_bgwriter AS w) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.checkpoints_timed, src.checkpoints_requested, src.checkpoint_write_time, src.checkpoint_sync_time, src.buffers_checkpoint, src.buffers_clean, src.max_written_clean, src.buffers_backend, src.buffers_backend_fsync, src.buffers_allocated, src.stats_reset FROM src